import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # State: (l, r) - coverage extends l to left, r to right from current pos
    # Pareto front: sorted by l ascending, r strictly decreasing
    # Use dict: l -> min_r
    states = {0: 0}  # l -> min_r

    for d in a:
        new_dict = {}
        for l, r in states.items():
            # go right: new (l+d, max(0, r-d))
            nl, nr = l + d, max(0, r - d)
            if nl not in new_dict or new_dict[nl] > nr:
                new_dict[nl] = nr
            # go left: new (max(0, l-d), r+d)
            nl, nr = max(0, l - d), r + d
            if nl not in new_dict or new_dict[nl] > nr:
                new_dict[nl] = nr
        # Pareto pruning: sort by l ascending, keep only when r strictly decreasing
        sorted_l = sorted(new_dict.keys())
        states = {}
        min_r = float('inf')
        for l in sorted_l:
            r = new_dict[l]
            if r < min_r:
                min_r = r
                states[l] = r

    print(min(l + r for l, r in states.items()))

t = int(input())
for _ in range(t):
    solve()
